import React, { useEffect, useState } from "react";
import Layout from "./../../components/shared/Layout/Layout";
import { useSelector } from "react-redux";
import API from "../../services/API";

const OrganisationPage = () => {
  const { user } = useSelector((state) => state.auth);
  const [data, setData] = useState([]);
  const [search, setSearch] = useState("");

  const getOrg = async () => {
    try {
      if (user?.role === "donar") {
        const { data } = await API.get("/inventory/get-orgnaisation");
        if (data?.success) setData(data?.organisations);
      }
      if (user?.role === "hospital") {
        const { data } = await API.get(
          "/inventory/get-orgnaisation-for-hospital",
        );
        if (data?.success) setData(data?.organisations);
      }
    } catch (error) {
      console.log(error);
    }
  };

  useEffect(() => {
    getOrg();
  }, [user]);

  const filtered = data.filter(
    (org) =>
      org.organisationName?.toLowerCase().includes(search.toLowerCase()) ||
      org.address?.toLowerCase().includes(search.toLowerCase()),
  );

  return (
    <Layout>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Syne:wght@600;700;800&family=DM+Sans:wght@300;400;500&display=swap');
        .org-page { font-family: 'DM Sans', sans-serif; }
        .org-top { margin-bottom: 28px; }
        .org-title { font-family: 'Syne', sans-serif; font-size: 26px; font-weight: 700; color: #fff; margin-bottom: 4px; }
        .org-title span { background: linear-gradient(90deg, #c084fc, #f472b6); -webkit-background-clip: text; -webkit-text-fill-color: transparent; background-clip: text; }
        .org-subtitle { font-size: 14px; color: rgba(255,255,255,0.4); }

        .org-info {
          padding: 16px 20px; border-radius: 14px; margin-bottom: 24px;
          background: rgba(168,85,247,0.07); border: 1px solid rgba(168,85,247,0.18);
          font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.6;
        }
        .org-info strong { color: rgba(255,255,255,0.8); }

        .org-search-wrap { margin-bottom: 24px; }
        .org-search {
          width: 100%; max-width: 380px; padding: 12px 16px;
          background: rgba(255,255,255,0.05); border: 1.5px solid rgba(255,255,255,0.1);
          border-radius: 12px; color: #fff; font-size: 14px;
          font-family: 'DM Sans', sans-serif; outline: none; transition: all 0.2s;
        }
        .org-search:focus { border-color: #a855f7; background: rgba(168,85,247,0.08); box-shadow: 0 0 0 3px rgba(168,85,247,0.12); }
        .org-search::placeholder { color: rgba(255,255,255,0.2); }

        .org-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(300px, 1fr)); gap: 16px; }
        .org-card {
          background: rgba(255,255,255,0.03); border: 1px solid rgba(255,255,255,0.08);
          border-radius: 18px; padding: 22px; transition: all 0.2s;
          position: relative; overflow: hidden;
        }
        .org-card::before {
          content: ''; position: absolute; top: 0; left: 0; right: 0; height: 2px;
          background: linear-gradient(90deg, #9333ea, #ec4899); opacity: 0;
          transition: opacity 0.2s;
        }
        .org-card:hover { border-color: rgba(168,85,247,0.3); transform: translateY(-3px); box-shadow: 0 8px 28px rgba(0,0,0,0.3); }
        .org-card:hover::before { opacity: 1; }
        .org-card-top { display: flex; align-items: center; gap: 14px; margin-bottom: 16px; }
        .org-avatar {
          width: 44px; height: 44px; border-radius: 12px; flex-shrink: 0;
          background: linear-gradient(135deg, #9333ea, #ec4899);
          display: flex; align-items: center; justify-content: center;
          font-size: 20px; box-shadow: 0 4px 12px rgba(147,51,234,0.3);
        }
        .org-name { font-family: 'Syne', sans-serif; font-size: 15px; font-weight: 700; color: #fff; margin-bottom: 2px; }
        .org-badge { display: inline-block; padding: 2px 8px; border-radius: 6px; font-size: 10px; font-weight: 600; background: rgba(34,197,94,0.12); color: #4ade80; }
        .org-divider { height: 1px; background: rgba(255,255,255,0.06); margin-bottom: 14px; }
        .org-detail { display: flex; align-items: flex-start; gap: 10px; margin-bottom: 10px; }
        .org-detail-icon { font-size: 14px; flex-shrink: 0; margin-top: 1px; }
        .org-detail-text { font-size: 13px; color: rgba(255,255,255,0.5); line-height: 1.4; }
        .org-detail-text a { color: #c084fc; text-decoration: none; }
        .org-detail-text a:hover { color: #f0abfc; }
        .org-donate-btn {
          width: 100%; margin-top: 16px; padding: 11px;
          border-radius: 11px; border: 1px solid rgba(168,85,247,0.3);
          background: rgba(168,85,247,0.1); color: #c084fc;
          font-size: 13px; font-weight: 600; font-family: 'DM Sans', sans-serif;
          cursor: pointer; transition: all 0.2s;
        }
        .org-donate-btn:hover { background: rgba(168,85,247,0.2); border-color: rgba(168,85,247,0.5); color: #e879f9; }

        .org-empty { text-align: center; padding: 80px 20px; }
        .org-empty-icon { font-size: 48px; margin-bottom: 12px; }
        .org-empty-text { font-size: 15px; color: rgba(255,255,255,0.3); }
        .org-count { font-size: 13px; color: rgba(255,255,255,0.3); margin-bottom: 20px; }
        .org-count span { color: #a855f7; font-weight: 600; }
      `}</style>

      <div className="org-page">
        <div className="org-top">
          <div className="org-title">
            Blood Bank <span>Organisations</span> 🏢
          </div>
          <div className="org-subtitle">
            Find a blood bank near you and donate today
          </div>
        </div>

        <div className="org-info">
          💡 <strong>How to use this page:</strong> These are registered blood
          banks and organisations on HemoLink. Find one near your address, visit
          them in person to donate blood, then record your donation on the{" "}
          <strong>My Donations</strong> page. You can email or call them before
          visiting!
        </div>

        <div className="org-search-wrap">
          <input
            className="org-search"
            type="text"
            placeholder="🔍  Search by name or address..."
            value={search}
            onChange={(e) => setSearch(e.target.value)}
          />
        </div>

        {filtered.length > 0 && (
          <div className="org-count">
            Showing <span>{filtered.length}</span> organisation
            {filtered.length !== 1 ? "s" : ""}
          </div>
        )}

        {filtered.length === 0 ? (
          <div className="org-empty">
            <div className="org-empty-icon">🏢</div>
            <div className="org-empty-text">
              {data.length === 0
                ? "No organisations registered yet"
                : "No results found for your search"}
            </div>
          </div>
        ) : (
          <div className="org-grid">
            {filtered.map((org) => (
              <div className="org-card" key={org._id}>
                <div className="org-card-top">
                  <div className="org-avatar">🏥</div>
                  <div>
                    <div className="org-name">{org.organisationName}</div>
                    <span className="org-badge">Accepting Donations</span>
                  </div>
                </div>
                <div className="org-divider" />
                {org.email && (
                  <div className="org-detail">
                    <span className="org-detail-icon">✉️</span>
                    <div className="org-detail-text">
                      <a href={`mailto:${org.email}`}>{org.email}</a>
                    </div>
                  </div>
                )}
                {org.phone && (
                  <div className="org-detail">
                    <span className="org-detail-icon">📞</span>
                    <div className="org-detail-text">{org.phone}</div>
                  </div>
                )}
                {org.address && (
                  <div className="org-detail">
                    <span className="org-detail-icon">📍</span>
                    <div className="org-detail-text">{org.address}</div>
                  </div>
                )}
                {org.website && (
                  <div className="org-detail">
                    <span className="org-detail-icon">🌐</span>
                    <div className="org-detail-text">
                      <a href={org.website} target="_blank" rel="noreferrer">
                        {org.website}
                      </a>
                    </div>
                  </div>
                )}
                <button
                  className="org-donate-btn"
                  onClick={() => {
                    navigator.clipboard?.writeText(org.email);
                    alert(
                      `${org.organisationName}'s email copied! Use it when recording your donation.`,
                    );
                  }}
                >
                  📋 Copy Email to Donate
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </Layout>
  );
};

export default OrganisationPage;
